DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
@den = random_coprime([2..8],[2..8]);
@num = (
  (random_coprime([1..8],[$den[0]]))[0],
  (random_coprime([1..8],[$den[1]]))[0]
);
$m = Fraction($num[0]/$den[0]);
$b = list_random(-1,1)*Fraction($num[1]/$den[1]);
$c = non_zero_random(-8,8);
$left = Formula("$m x + $b")->reduce;
$right = Formula("$c");
$sol = ($c - $b)/$m;
Context("FiniteSolutionSets");
$solution = Formula("{$sol}");
$lcd = lcm(@den);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the given equation. Practice clearing the denominator(s) as a first step.

[`[$left] = [$right]`]

[@KeyboardInstructions('What LCD will you use?')@]**

[_]{$lcd}{4}

[@KeyboardInstructions('Solve the equation.')@]**

[_]{$solution}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
